local function OnControl(self, control, down, ...) local owner = self.owner if owner then owner.dycIsManualEquipOrUnequip = true owner:DoTaskInTime(0x0, function() owner.dycIsManualEquipOrUnequip = false end) end return self.dycOldOnControl(self, control, down, ...) end local function DYCEquipSlot(self) self.dycOldOnControl = self.OnControl self.OnControl = OnControl end return DYCEquipSlot 